@ARTICLE{10.1016/j.tox.2025.154362,
	author = {Gong J and Park IG and Hwang S and Cho J and Lee MJ and Kim M and Kang J and An S and Noh M},
	title = {Interaction-profile cheminformatic read-across identifies the UV filter benzophenone-4 as a PPARγ agonist and potential obesogen.},
	abstract = {Obesogens are chemicals, often encountered as environmental contaminants, that disrupt metabolic regulation and promote obesity. Here, we present a cheminformatics framework that integrates interaction-profile docking simulations with cluster-level enrichment analysis to enhance read-across and prioritize candidate environmental metabolic disruptors. Protein-ligand contact features from docking to obesity-related nuclear receptors were summarized at the pose level and combined into a 327-dimensional interaction-profile descriptor. Dimensionality-reduced descriptors from 6022 Tox21 compounds were clustered, and enrichment analysis against Tox21 assay results identified clusters associated with specific nuclear receptor activities. One cluster was selectively enriched for peroxisome proliferator-activated receptor γ (PPARγ) agonists. Although benzophenone-4 (BP-4, sulisobenzone), a sunscreen UV filter in this cluster, is labeled as inactive in Tox21, experimental validation confirmed selective PPARγ binding and recruitment of SRC-2 and PGC-1α coactivators. In human bone marrow-derived mesenchymal stem cells, BP-4 promoted adipogenic differentiation, lipid accumulation, and adiponectin production, establishing its potential as an environmental obesogen. This study demonstrates the power of combining interaction-profile read-across with functional assays to predict environmental metabolic disruptors and provides a mechanistic template for systematic chemical safety evaluation.},
	doi = {10.1016/j.tox.2025.154362},
	pmid = {41325878 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/mnfr.70341,
	author = {Das P and Kar R and Panchali T and Dutta A and Phoujdar M and Ghosh K and Pradhan S},
	title = {Antiobesity Efficacy of Marine Tapra Fish (Opisthopterus tardoore) Oil in High-Fat Diet-Induced Obese Mice by Activating Lipolysis and Suppressing Adipose Inflammation.},
	abstract = {The present study sought to elucidate the potentiality of oil extracted from Opisthopterus tardoore (OT, marine fish available in Bay of Bengal region) on diet induced obesity and explored into the primary molecular process that underlies these effects. Male Swiss albino mice were fed a high-fat diet for 12 weeks to develop obesity, and different doses of OT (200, 400, and 600 mg/kg/day) oil was administered orally for 4 weeks. Following treatment, body weight, biochemical, histological, and genomic parameters were assessed from liver and adipose tissues (ATs). Significant reductions were observed in body weight, lipid profiles, blood glucose, liver, and visceral AT weight, correlated with decreased adipocyte size by supplementation with OT oil. The fish oil significantly upregulates mRNA levels of lipolytic factors such as adiponectin, peroxisome proliferator-activated receptor-α, carnitine palmitoyl transferase-1, lipoprotein lipase, and antiinflammatory cytokines, including interleukin-1 receptor antagonist (IL-1Ra), IL-10, than those of high-fat diet group. Concomitantly, adipogenesis and fatty acid synthesis were arrested by reduction of lipogenic genes, including leptin, fatty acid synthase, sterol regulatory element binding protein-1c, and proinflammatory markers (tumor necrosis factor-α, IL-6, inducible nitric oxide synthase, and IL-1β) in adipocytes. The results therefore concluded that OT oil exhibited lipid-lowering along with antiinflammatory properties.},
	doi = {10.1002/mnfr.70341},
	pmid = {41321257 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.tice.2025.103245,
	author = {Gong H and Song Y and Yang D and Jiang C and Jiao R and Ma Y and Raza SHA and Zhang J and Wei D},
	title = {Analysis of WNT5A as a key regulator of intramuscular fat deposition in muscle-adipocyte co-cultures.},
	abstract = {The coordinated development of skeletal muscle and intramuscular adipose tissue in animals essentially determines meat yield and quality, a process co-regulated by multiple genes. Using a co-culture model of bovine skeletal muscle cells (SMCs) and intramuscular adipocytes (IMAs), integrated with transcriptomic sequencing and bioinformatic analyses, key candidate genes coregulating muscle development and fat deposition were identified. Three potential coregulators-WNT5A, APOE, and BDKRB2-were selected. Protein-protein interaction (PPI) network analysis, along with tissue and cellular expression profiling, indicates that WNT5A potentially interacts with key protein markers of adipogenesis and myogenesis. Furthermore, it is highly expressed in both adipose and muscle tissues. Pathway enrichment analysis revealed significant enrichment of WNT5A in the Wnt signaling pathway. These findings suggest that WNT5A plays a dual regulatory role in the development of both skeletal muscle and intramuscular fat (IMF). This finding lays a solid theoretical foundation for deciphering the molecular mechanisms of muscle-fat deposition in beef cattle and for improving meat quality.},
	doi = {10.1016/j.tice.2025.103245},
	pmid = {41314095 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/ptr.70108,
	author = {Tie F and Hu N and Dong Q and Wang H},
	title = {Vitisin A Regulates Lipid Metabolism in 3T3-L1 Adipocytes and High-Fat Diet-Induced Obese Mice.},
	journal = {Phytother Res},
	year = {2026},
	abstract = {Obesity is a leading cause of various metabolic disorders, and its prevalence is rapidly increasing globally. In this study, we investigated the potential lipid-inhibitory and anti-obesity effects of oligostilbene compounds derived from Iris lactea in 3T3-L1 adipocytes. Particularly, Vitisin A on lipid accumulation in 3T3-L1 adipocytes, as well as on lipid metabolism in HFD-induced obese mice. The 3T3-L1 adipocytes and HFD-induced obese mice model were used in the study. In 3T3-L1 adipocytes, MTT assay, oil red O staining, transmission electron microscopy, MitoSox/DCFH-DA probe, and western blotting were used to assess specific indicators. In HFD-induced obese mice, lipid profile and hepatic injury were analyzed in the liver samples, histological sections were prepared and liver lipidomics analysis was performed, and western blotting was used to analyze the proteins associated with lipid lowering in Vitisin A. Vitisin A significantly reduced intracellular lipid accumulation, inhibited preadipocyte differentiation, and improved mitochondrial function in 3T3-L1 adipocytes. Transcriptomics analysis revealed notable changes in adipogenic gene expression in Vitisin A-treated 3T3-L1 cells. Furthermore, Vitisin A administration in HFD-induced obese mice resulted in smaller adipose depots and lower lipid concentrations. Lipidomics analysis indicated that Vitisin A modified lipid metabolic pattern in obese mice, significantly impacting triglycerols (TGs), phosphatidylcholines (PCs), and phosphatidylethanolamines (PEs). Mechanistic study revealed that Vitisin A is likely to activate the PPARγ/PGC-1α signaling pathway to ameliorating lipid metabolism disorders. The lipid-inhibitory and anti-obesity effects of Vitisin A from Iris lactea are regulated by lipid homeostasis and metabolism.},
	doi = {10.1002/ptr.70108},
	pmid = {41277332 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jnutbio.2025.110190,
	author = {Yahya MA and Alshammari GM and Eleawa SM and Amawi K and Alkhateeb M and Al-Farga AM and Alshaikhli H and AlFaris NA and Alotaibi SN},
	title = {Decoding the anti-obesity mechanisms of isoliquiritigenin: AMPK activation modulates adipogenesis, lipolysis, oxidative stress, and inflammation in high-fat diet rat models.},
	journal = {J Nutr Biochem},
	year = {2026},
	abstract = {This study investigated the effects of Isoliquiritigenin (ISL) on adiposity in Wistar rats fed a high-fat diet (HFD), positing that ISL mitigates adiposity by inhibiting adipogenesis and promoting lipolysis via AMPK activation. Adult male Wistar rats were divided into six groups (n=8): Control (vehicle), Control + ISL (40 mg/kg), HFD (vehicle), HFD + ISL (20 mg/kg), HFD + ISL (40 mg/kg), and HFD + ISL (40 mg/kg) + Dorsomorphin (0.2 mg/kg) for 12 weeks. In a dose-dependent manner, ISL (thrice a week) significantly attenuated the increase in body weight and adipocyte size, improving glucose and insulin tolerance, HbA1c, and HOMA-IR without affecting food intake in HFD rats. Particularly, the higher dose of ISL (40 mg/kg) significantly increased the phosphorylation of AMPK (+193.3%), resulting in a p-AMPK/AMPK activity ratio increase of 191.0% in the white adipose tissue (WAT) of HFD rats. This dose also reduces body weight (24.6%), weight gain (28.7), fat deposit weight (-39.2% %), HOMA-IR (-67.62%), and serum triglycerides (-62.4%), cholesterol (56.7%), IL-6 (-66.1%) and TNF-α (-79.5%) in these HFD rats. It also increased p-ACC levels (+86.7%), Nrf2 mRNA (+392.7%), and PPARα mRNA (+255.0%), as well as the levels of HSL (+149.7%) and ATGL (139.62%). ISL (40 mg/kg) also decreased WAT levels of IL-6 (-57.86%), TNF-α (-74.96%), mRNA of SREBP1 (-38/8%), FAS (-50%) and NF-kB (58.8%), and levels of PLIN1 (-50.1) in these HFD rats. Dorsomorphin treatment reversed these effects in ISL + HFD rats. In conclusion, ISL demonstrates anti-obesity effects in HFD-induced rats through AMPK activation.},
	doi = {10.1016/j.jnutbio.2025.110190},
	pmid = {41274316 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.metabol.2025.156439,
	author = {Pedersen L and Gliniak CM and Dale TM and Zhu Q and Li C and Funcke JB and Crewe C and Luo J and Palluth L and Zhu Y and Scherer PE},
	title = {Induction of Yin Yang 1 (YY1) overexpression in mature adipocytes promotes dysfunctional adipose tissue and systemic insulin resistance in mice.},
	journal = {Metabolism},
	year = {2026},
	abstract = {The ubiquitous transcription factor Ying Yang 1 (YY1) plays a fundamental role in multiple biological processes and is believed to regulate up to 10 % of all human genes. In thermogenic brown adipose tissue, YY1 has been linked to controlling mitochondrial gene expression and regulating cellular oxidative respiration, protecting against diet-induced obesity and alterations in energy balance. The role of YY1 in non-thermogenic, white adipose tissue, on the other hand, remains largely unknown. Here, we show that adipocyte-specific induction of YY1 promotes dysfunctional adipose tissue and systemic insulin resistance in mice. Long-term YY1 induction in mature adipocytes leads to reduced weight gain, systemic insulin resistance, and increased liver steatosis in comparison to control littermates. In contrast, brown adipose tissue-specific YY1 overexpression has little effect on mice fed a high-fat diet. In an obesogenic environment, acute ectopic adiponectin promoter-driven YY1 expression promotes weight loss, cell death, and adipose tissue inflammation. Underlying the observed reduction in adipose tissue mass, we find that YY1 controls gene networks related to adipose tissue expansion, lipid anabolic pathways (hypertrophy), and hyperplasia (adipogenesis). Taken together, our results demonstrate novel roles of Yy1 in white adipose tissue. This versatile transcription factor regulates central aspects of white adipose tissue biology that are essential for maintaining whole-body physiology.},
	doi = {10.1016/j.metabol.2025.156439},
	pmid = {41265559 [Indexed for MEDLINE]}
}
